var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"인류 통합 방위군 제1 방위선, 거점 기지","JPN":"人類統合防衛軍第1防衛線、拠点基地","ENG":"Base, United Humankind Defense Force's 1st Defense Line","TWN":"人類共同保衛軍第一防線基地","THA":"ฐานทัพ แนวป้องกันที่ 1 กองกำลังป้องกันมนุษยชาติยูไนเต็ด","VTN":"Căn cứ, Phòng Tuyến thứ 1 của Lực Lượng Phòng Vệ Nhân Loại Thống Nhất","SCN":"人类综合防卫军第1防线，据点基地","DEU":"Basis, 1. Verteidigungslinie der Verteidigungsstreitkräfte der vereinigten Menschheit","FRA":"Base de la 1e ligne de défense des Forces de défense unies de l'humanité"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"아포리아 공략 작전 후, 5개월 뒤","JPN":"アポリア攻略作戦から5か月後","ENG":"5 months after Operation Aporia","TWN":"攻陷阿波利亞後經過5個月","THA":"5 เดือนหลังจากปฏิบัติการ อาโพเรีย","VTN":"5 tháng sau Chiến dịch Aporia","SCN":"阿波利亚作战，5个月后","DEU":"5 Monate nach der Operation „Aporia“","FRA":"5 mois après l'opération Aporia"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"사령관님, 현 시간부로 델타 세븐은 패스파인더 분대로 인원을 재편성.","JPN":"司令官、現時刻よりデルタセブンはパスファインダー分隊として人員を再編成。","ENG":"Commander, Delta Seven has been reassigned to the Pathfinder Squad as of this moment.","TWN":"司令官，第七三角洲部隊開拓者分隊，已重新進行人員整頓。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"물자 준비 및 항해에 필요한 모든 준비를 마쳤습니다.","JPN":"物資の用意および航海に必要な準備をすべて終わらせましたことを。","ENG":"All preparations required for the voyage, including supplies, are complete.","TWN":"已完成物資籌備及航行所需的一切準備。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"이에 보고드리겠습니다!","JPN":"ここに報告いたします！","ENG":"Reporting as ordered!","TWN":"以上，報告完畢！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"반드시 가야 하겠나, 소령?","JPN":"どうしても行くのか、少佐？","ENG":"Must you go, Major?","TWN":"一定要走嗎，少校？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"아직 우리 세계는 아포리아 사태 때 입은 상처를 완전히 회복하지 못했어.","JPN":"まだ私たちの世界はアポリアによる傷が完全に癒えていない。","ENG":"Our world has not yet fully recovered from the wounds caused by the Aporia insident.","TWN":"我們的世界還沒能從阿波利亞事件中完全恢復。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"인류의 결집을 위해서는 자네들과 같은 영웅의 힘이 반드시 필요하네.","JPN":"人類結束のためには、君たちのような英雄の力が不可欠だ。","ENG":"To unite mankind, a hero like yourself is crucial.","TWN":"需要像你們這樣的英雄來招聚大家。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"아니요.","JPN":"いいえ。","ENG":"I think otherwise, sir.","TWN":"不。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"믿기 힘드시겠지만, 제 눈에 깃든 고유 무장 및 아이기스함은 그 존재 자체만으로 이 세계의 침식률을 끌어올릴 겁니다.","JPN":"信じ難いことかと思いますが、私の眼に移植された固有武装およびアイギス艦は存在しているだけで、この世界の侵食率を大きく引き上げてしまいます。","ENG":"It may be hard to believe, but the Unique Gear in my right eye and the existence of Aegis will only increase the Corruption rate of this world.","TWN":"聽起來可能會讓人難以相信，但我眼中的這個專屬裝備，以及埃癸斯的存在，會提高我們世界的侵蝕率。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"그렇게 되면, 머지않아 아포리아 사태와 같은 일이 또 발생하겠죠.","JPN":"そうなったら、そう遠くない将来、アポリア事件のようなことが再び起きてしまうでしょう。","ENG":"If that happens, another crisis like Aporia is bound to happen in the near future.","TWN":"那樣的話，不用多久，就又會發生與阿波利亞事件一樣的事情。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"그럼 우리 세계는 멸망을 피할 수가 없다는 말인가?","JPN":"それじゃ、私たちの世界は滅亡を避けられないということか？","ENG":"Are you saying that our world's end is inevitable?","TWN":"你是說我們的世界無法逃脫滅亡的命運嗎？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"이론 상으로는 그렇습니다.","JPN":"理論的にはそうです。","ENG":"In theory, yes, that is correct.","TWN":"理論上是這樣沒錯。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"그 안토노프라는 자가 제시했던 이론에서는 그렇죠.","JPN":"あのアントノフという者が話していた理論だとそうです。","ENG":"At least according to Antonov's theory.","TWN":"至少在那個安東諾夫提出的理論中是這樣的。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"그게 무슨?","JPN":"どういう意味だ？","ENG":"What?","TWN":"你的意思是？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"이번 사태로 분명해진 건, <color=#ffd34c>한 가지</color>밖에 없습니다.","JPN":"今回の事件で明確になったのは、<color=#ffd34c>一つ</color>だけです。","ENG":"<color=#ffd34c>One thing</color> has been made clear to me from this crisis.","TWN":"經過這次事件，可以確認的只有<color=#ffd34c>一件事</color>。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};